const body = $input.first().json.body;
const now = new Date().toLocaleDateString('es-ES', {
  year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit'
});

const esc = s => String(s || '').replace(/'/g, "''").substring(0, 200);

const planMap = { base: 'base', pro: 'pro' };
const planNorm = planMap[(body.plan || '').toLowerCase()] || 'sin_definir';

return [{
  json: {
    nombre:      body.nombre    || '',
    email:       body.email     || '',
    telefono:    body.telefono  || '',
    especialidad: body.especialidad || '',
    plan:        body.plan      || 'no especificado',
    fecha:       now,
    source:      'Landing Nervia',
    // Campos para DB (escapados)
    nombreEsc:       esc(body.nombre),
    emailEsc:        esc(body.email),
    telefonoEsc:     esc(body.telefono),
    especialidadEsc: esc(body.especialidad),
    mensajeEsc:      esc(body.mensaje),
    planNorm,
    utmSource: esc(body.utm_source),
    utmMedium: esc(body.utm_medium),
    // Mensaje Telegram
    msg: `🎯 *Nuevo lead Nervia*\n\n👤 ${body.nombre}\n📧 ${body.email}\n📱 ${body.telefono || '—'}\n🏥 ${body.especialidad}\n📋 Plan: ${body.plan}\n\n📅 ${now}`
  }
}];
